function AppScreenshot({ bordered = false, dark = false, size = "default" }: { bordered?: boolean; dark?: boolean; size?: "default" | "wide" | "full" }) {
  const imageSrc = dark ? "/assets/hero-sections/app-dashboard-dark.png" : "/assets/hero-sections/app-dashboard-light.png"
  const cropClass = size === "wide"
    ? "left-0 top-0 h-[92%] w-[92%] object-contain object-left-top"
    : size === "full"
      ? "left-0 top-0 h-full w-full object-contain object-left-top"
      : "left-0 top-0 h-[118%] w-[118%] object-left-top"

  return (
    <div className={cn(
      "relative w-full overflow-hidden rounded-2xl shadow-2xl",
      size === "wide" && "min-w-[560px] md:min-w-[1120px]",
      size === "full" && "mx-auto max-w-5xl",
      bordered && (dark ? "border border-white/10" : "border border-slate-200"),
      dark ? "bg-slate-950 text-slate-200 shadow-black/35" : "bg-white text-slate-900 shadow-slate-900/20"
    )}>
      <div className={cn("relative overflow-hidden", size === "full" ? "aspect-[16/9]" : "aspect-[16/10]")}>
        <img
          alt=""
          className={cn("absolute max-w-none object-cover", cropClass)}
          src={imageSrc}
        />
        <div className={cn("pointer-events-none absolute inset-0", dark ? "bg-[radial-gradient(circle_at_20%_0,rgba(255,255,255,0.08),transparent_26%),linear-gradient(to_bottom,rgba(2,6,23,0),rgba(2,6,23,0.20))]" : "bg-[radial-gradient(circle_at_18%_0,rgba(99,102,241,0.08),transparent_24%),linear-gradient(to_bottom,rgba(255,255,255,0),rgba(248,250,252,0.18))]")} />
        <div className={cn("pointer-events-none absolute inset-0 rounded-[inherit] ring-1 ring-inset", dark ? "ring-white/10" : "ring-slate-950/10")} />
      </div>
    </div>
  )
}

