                {variant === "banner-with-link" || variant === "banner-left-aligned" || variant === "banner-bottom-aligned" || isBannerFloating ? <span className={cn("text-sm font-semibold", isBannerDark || isBannerBrand ? "text-white" : "text-indigo-600")}>Learn more <span aria-hidden>→</span></span> : null}
