              {variant === "combobox-page" && <div className="rounded-md border bg-background p-3 text-sm">Search teammates...</div>}
              {variant === "input-group-page" && <div className="flex rounded-md border bg-background text-sm"><span className="border-r px-3 py-2 text-muted-foreground">https://</span><span className="flex-1 px-3 py-2 text-muted-foreground">workspace.askewly.com</span></div>}
