                <Cell className={cn("border-b", dark ? "border-white/10 text-slate-300" : "border-slate-100 text-slate-500", mobileMode === "stacked" && "hidden md:table-cell")}>{user.title}{multiline && <p className={cn("mt-1", dark ? "text-slate-500" : "text-slate-400")}>{user.team}</p>}</Cell>
