    if (variant === "table-list-hidden-mobile") return <Shell dark={false}><Header dark={false} /><UsersTable dark={false} mobileMode="hidden" /></Shell>
    if (variant === "table-list-avatars-multiline") return <Shell><Header /><UsersTable dark avatars multiline /></Shell>
