          {menuLeft && <div className="hidden items-center gap-2 md:flex">{navItem("Dashboard", true)}{navItem("Team")}{navItem("Projects")}{navItem("Calendar")}</div>}
          {centered && <div className="mx-auto hidden md:block"><SearchBox compact /></div>}
          {column ? <div className="mx-auto hidden flex-1 md:block"><SearchBox /></div> : null}
