    const isMultiNarrow = variant === "shell-multi-narrow-sidebar" || variant === "shell-multi-narrow-sidebar-header"
    const isMultiSecondaryRight = variant === "shell-multi-secondary-right"
    const isMultiSticky = variant === "shell-multi-sticky-columns"
    const isMultiDark = variant === "shell-multi-secondary-right" || variant === "shell-multi-narrow-sidebar-header"
